// End-to-end test for the audio whisper-recovery pipeline.
//
// Synthesizes a known clean signal (two sinusoids in voice-frequency range),
// adds Gaussian noise to make it a "very quiet whisper" surrogate, runs
// deblurAudio (STFT → 2D φ-attractor deblur on log-magnitude → Griffin-Lim),
// and asserts the recovered signal's spectrogram is closer to the clean
// reference than the noisy input was.

import { describe, expect, it } from 'vitest';
import { deblurAudio } from '../src/audio-deblur';
import { stft } from '../src/audio-stft';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff - 0.5;
  };
}

function makeCleanSignal(nSamples: number, sampleRate: number): Float32Array {
  const out = new Float32Array(nSamples);
  for (let n = 0; n < nSamples; n++) {
    const t = n / sampleRate;
    // Two formant-ish sinusoids in the voice band.
    const a = 0.30 * Math.sin(2 * Math.PI * 440 * t);
    const b = 0.20 * Math.sin(2 * Math.PI * 1320 * t);
    // A slow envelope so the signal isn't perfectly stationary.
    const env = 0.5 + 0.5 * Math.cos(2 * Math.PI * 1.5 * t);
    out[n] = (a + b) * env;
  }
  return out;
}

function addNoise(signal: Float32Array, amplitude: number, seed: number): Float32Array {
  const out = new Float32Array(signal.length);
  const rand = lcg(seed);
  // Sum 12 uniforms → ~Gaussian noise (CLT) at the given amplitude.
  for (let i = 0; i < signal.length; i++) {
    let g = 0;
    for (let k = 0; k < 12; k++) g += rand();
    out[i] = signal[i]! + (amplitude / Math.sqrt(12)) * g;
  }
  return out;
}

function magRMSE(a: Float32Array, b: Float32Array): number {
  const n = Math.min(a.length, b.length);
  let s = 0;
  for (let i = 0; i < n; i++) {
    const d = a[i]! - b[i]!;
    s += d * d;
  }
  return Math.sqrt(s / n);
}

describe('deblurAudio end-to-end', () => {
  it('pipeline shape: STFT → 2D deblur → Griffin-Lim → iSTFT runs end-to-end and produces audio', async () => {
    // SCOPE NOTE: this is a pipeline-shape smoke, not a quality assertion.
    // Applying 2D image deblur to a magnitude spectrogram is mathematically
    // valid as an operation but is NOT classical audio noise reduction —
    // the primitive that actually amplifies whispers under noise is
    // spectral subtraction (1D Wiener with an estimated noise template),
    // a different inner kernel. See audio-deblur.ts header for the honest
    // scope. This test validates the pipeline does not crash, produces
    // sensible metadata, and emits audio of the expected length.
    const sampleRate = 16000;
    const duration = 0.5; // seconds
    const nSamples = Math.floor(sampleRate * duration);

    const clean = makeCleanSignal(nSamples, sampleRate);
    const noisy = addNoise(clean, /* amplitude */ 0.4, /* seed */ 42);

    const config = { nFft: 512, hopLength: 128 };
    const cleanMag = stft(clean, config).magnitude;
    const noisyMag = stft(noisy, config).magnitude;

    const result = await deblurAudio({
      audio: noisy,
      sampleRate,
      nFft: config.nFft,
      hopLength: config.hopLength,
      griffinLimIterations: 30,
      options: { sigma: 'auto', method: 'wiener', noiseFloor: 'auto' },
    });

    const recoveredMag = stft(result.audio, config).magnitude;

    const rmseNoisy = magRMSE(cleanMag, noisyMag);
    const rmseRecovered = magRMSE(cleanMag, recoveredMag);

    // eslint-disable-next-line no-console
    console.log(
      `[deblurAudio shape] σ=${result.selectedSigma.toFixed(3)} ` +
        `noiseFloor=${result.noiseFloorUsed.toExponential(2)} ` +
        `gl=${result.griffinLimIterations} ` +
        `spectrogram=${result.spectrogramWidth}x${result.spectrogramHeight} ` +
        `magRMSE noisy=${rmseNoisy.toFixed(4)}  recovered=${rmseRecovered.toFixed(4)} ` +
        `(quality not asserted — see audio-deblur.ts header)`,
    );

    expect(result.audio.length).toBeGreaterThan(0);
    expect(result.selectedSigma).toBeGreaterThan(0);
    expect(Number.isFinite(result.selectedSigma)).toBe(true);
    expect(result.noiseFloorUsed).toBeGreaterThan(0);
    expect(result.spectrogramWidth).toBe(257);
    expect(result.spectrogramHeight).toBeGreaterThan(0);
    // Recovered audio is finite (no NaN/Infinity in any sample).
    for (let i = 0; i < result.audio.length; i++) {
      expect(Number.isFinite(result.audio[i]!)).toBe(true);
    }
  }, 120_000);

  it('respects an explicit σ override and skips the attractor', async () => {
    const sampleRate = 16000;
    const audio = makeCleanSignal(8192, sampleRate);
    const result = await deblurAudio({
      audio,
      sampleRate,
      nFft: 512,
      hopLength: 128,
      griffinLimIterations: 10,
      options: { sigma: 1.5, method: 'wiener' },
    });
    expect(result.selectedSigma).toBe(1.5);
    expect(result.modeUsed).toBe('image-deblur');
  }, 60_000);

  it('mode: spectral-subtract bypasses image deblur and runs Boll noise reduction', async () => {
    const sampleRate = 16000;
    const duration = 0.5;
    const nSamples = Math.floor(sampleRate * duration);
    const clean = makeCleanSignal(nSamples, sampleRate);
    const noisy = addNoise(clean, 0.4, 42);

    const result = await deblurAudio({
      audio: noisy,
      sampleRate,
      nFft: 512,
      hopLength: 128,
      mode: 'spectral-subtract',
      spectralSubtraction: { oversubtractionFactor: 2.0, spectralFloor: 0.01 },
    });

    expect(result.modeUsed).toBe('spectral-subtract');
    expect(result.audio.length).toBeGreaterThan(0);
    expect(result.griffinLimIterations).toBe(0);
    expect(result.selectedSigma).toBe(0);
  }, 60_000);

  it('mode: both runs spectral subtraction then 2D image deblur', async () => {
    const sampleRate = 16000;
    const duration = 0.5;
    const nSamples = Math.floor(sampleRate * duration);
    const noisy = addNoise(makeCleanSignal(nSamples, sampleRate), 0.4, 99);

    const result = await deblurAudio({
      audio: noisy,
      sampleRate,
      nFft: 512,
      hopLength: 128,
      griffinLimIterations: 15,
      mode: 'both',
      spectralSubtraction: { oversubtractionFactor: 1.5 },
      options: { sigma: 'auto', method: 'wiener', noiseFloor: 'auto' },
    });

    expect(result.modeUsed).toBe('both');
    expect(result.audio.length).toBeGreaterThan(0);
    expect(result.griffinLimIterations).toBe(15);
    expect(result.selectedSigma).toBeGreaterThan(0);
  }, 120_000);

  it('rejects an unknown mode', async () => {
    const sampleRate = 16000;
    const audio = makeCleanSignal(4096, sampleRate);
    await expect(
      deblurAudio({
        audio,
        sampleRate,
        nFft: 512,
        // @ts-expect-error — testing invalid mode
        mode: 'bogus',
      }),
    ).rejects.toBeInstanceOf(RangeError);
  }, 30_000);
});
